# =============================================================
# LOAD ARTEFACTS
# =============================================================
@st.cache_resource(show_spinner="Loading models...")
def load_bundle():
    if not BUNDLE_PATH.exists(): return None
    return joblib.load(BUNDLE_PATH)

@st.cache_data(show_spinner=False)
def load_data():
    if not DATA_PATH.exists(): return pd.DataFrame()
    return pd.read_parquet(DATA_PATH)

@st.cache_data(show_spinner=False)
def load_registry():
    if not REGISTRY_PATH.exists():
        return {"wg_model_name":"XGBoost_WG","ct_model_name":"GradientBoosting_CT",
                "wg_test_r2":0.9608,"ct_test_r2":0.9990,
                "wg_test_rmse":1.621,"ct_test_rmse":0.839,
                "feature_count":50}
    with open(REGISTRY_PATH, encoding="utf-8") as fh:
        return json.load(fh)

bundle   = load_bundle()
df_raw   = load_data()
registry = load_registry()

WG_R2   = registry.get("wg_test_r2",   0.9608)
CT_R2   = registry.get("ct_test_r2",   0.9990)
WG_RMSE = registry.get("wg_test_rmse", 1.621)
CT_RMSE = registry.get("ct_test_rmse", 0.839)
WG_NAME = registry.get("wg_model_name","XGBoost_WG")
CT_NAME = registry.get("ct_model_name","GradientBoosting_CT")

# =============================================================
# SIDEBAR
