def card(val, lbl, sub="", color="#60a5fa"):
    s = f"<div class='mc-sub'>{sub}</div>" if sub else ""
    return (f"<div class='mc'><div class='mc-val' style='color:{color};'>{val}</div>"
            f"<div class='mc-lbl'>{lbl}</div>{s}</div>")

def gauge(score, lbl, tgt, color):
    fig = go.Figure(go.Indicator(
        mode="gauge+number+delta",
        value=score,
        delta={"reference":tgt,"suffix":"%",
               "increasing":{"color":"#4ade80"},"decreasing":{"color":"#f87171"}},
        title={"text":lbl,"font":{"size":13,"color":"#e2e8f0"}},
        number={"suffix":"%","font":{"size":26,"color":color}},
        gauge={
            "axis":{"range":[0,100],"tickcolor":"#334155","dtick":20},
            "bar":{"color":color,"thickness":.28},
            "bgcolor":"#0d1931","bordercolor":"#1e3054",
            "steps":[
                {"range":[0,40], "color":"#1c0a0a"},
                {"range":[40,60],"color":"#1c1400"},
                {"range":[60,80],"color":"#071a10"},
                {"range":[80,100],"color":"#052e16"},
            ],
            "threshold":{"line":{"color":"#ef4444","width":3},"thickness":.82,"value":tgt},
        }))
    fig.update_layout(height=230,**{k:v for k,v in PD.items() if k!="template"},template="plotly_dark")
    return fig

def vigor_badge(cls):
    if "Excellent" in cls: return f'<span class="b-exc">🟢 {cls}</span>'
    if "Good"      in cls: return f'<span class="b-goo">🟡 {cls}</span>'
    return                        f'<span class="b-poo">🔴 {cls}</span>'

