    with tab4:
        grp_c = ("state" if "state" in dff.columns and dff["state"].notna().sum()>3
                 else ("variety" if "variety" in dff.columns else "vigor_class"))
        fld=dff.groupby(grp_c).agg(
            Lots=("WG","count"),Avg_WG=("WG","mean"),Avg_CT=("CT","mean"),
            Exc_Pct=("vigor_class",lambda x:(x=="Excellent").mean()*100 if "vigor_class" in dff.columns else 0),
            Poor_Pct=("vigor_class",lambda x:(x=="Poor").mean()*100 if "vigor_class" in dff.columns else 0),
        ).round(2).sort_values("Avg_WG",ascending=False).head(25).reset_index()

        def badge(v,thr,lbls,stls):
            for t,l,s in zip(thr,lbls,stls):
                if v>=t: return f'<span class="{s}">{l}</span>'
            return '<span class="b-poo">Poor</span>'

        rows=""
        for _,row in fld.iterrows():
            wb=badge(row["Avg_WG"],[80,70,60],["High Quality","Acceptable","Marginal"],["b-exc","b-goo","b-poo"])
            cb=badge(row["Avg_CT"],[70,55,40], ["High Quality","Acceptable","Marginal"],["b-exc","b-goo","b-poo"])
            ew=min(row["Exc_Pct"],100); pw=min(row["Poor_Pct"],100)
            rows+=(f'<tr style="border-bottom:1px solid #1e2d4a;">'
                   f'<td style="padding:9px 12px;font-weight:700;color:#ffffff;font-size:14px;">{row[grp_c]}</td>'
                   f'<td style="padding:9px;text-align:center;color:#ffffff;font-size:14px;">{int(row["Lots"]):,}</td>'
                   f'<td style="padding:9px;color:#ffffff;font-size:14px;">{row["Avg_WG"]:.1f}%&nbsp;{wb}</td>'
                   f'<td style="padding:9px;color:#ffffff;font-size:14px;">{row["Avg_CT"]:.1f}%&nbsp;{cb}</td>'
                   f'<td style="padding:9px;"><div style="background:#052e16;width:{ew:.0f}%;height:7px;border-radius:4px;margin-bottom:2px;"></div>'
                   f'<span style="font-size:13px;color:#4ade80;font-weight:600;">{ew:.1f}%</span></td>'
                   f'<td style="padding:9px;"><div style="background:#1c0a0a;width:{pw:.0f}%;height:7px;border-radius:4px;margin-bottom:2px;"></div>'
                   f'<span style="font-size:13px;color:#f87171;font-weight:600;">{pw:.1f}%</span></td>'
                   f'</tr>')

        st.markdown(f"""
        <div style="overflow-x:auto;border-radius:10px;border:1px solid #1e3054;">
          <table style="width:100%;border-collapse:collapse;background:#0d1931;color:#ffffff;">
            <thead><tr style="background:#122040;border-bottom:2px solid #1e3054;">
              <th style="padding:13px 12px;text-align:left;color:#60a5fa;font-size:15px;font-weight:700;">{grp_c.title()}</th>
              <th style="padding:13px;text-align:center;color:#60a5fa;font-size:15px;font-weight:700;">Lots</th>
              <th style="padding:13px;color:#60a5fa;font-size:15px;font-weight:700;">Avg WG</th>
              <th style="padding:13px;color:#60a5fa;font-size:15px;font-weight:700;">Avg CT</th>
              <th style="padding:13px;color:#34d399;font-size:15px;font-weight:700;">% Excellent</th>
              <th style="padding:13px;color:#ef4444;font-size:15px;font-weight:700;">% Poor</th>
            </tr></thead>
            <tbody>{rows}</tbody>
          </table></div>""", unsafe_allow_html=True)

        st.markdown("<br/>",unsafe_allow_html=True)
        d1,d2,d3=st.columns(3)
        for dc,col_,title_,clr_ in [(d1,"WG","WG Distribution","#3b82f6"),(d2,"CT","CT Distribution","#34d399"),(d3,"CT_WG_Ratio","CT/WG Ratio","#a78bfa")]:
            with dc:
                fig=px.histogram(dff[col_].dropna(),nbins=26,title=title_,color_discrete_sequence=[clr_])
                fig.update_layout(height=240,showlegend=False,**PD,
                    title_font_color="#ffffff",
                    xaxis=dict(tickfont=dict(color="#ffffff",size=11),gridcolor="#1e3054",title_font=dict(color="#ffffff")),
                    yaxis=dict(tickfont=dict(color="#ffffff",size=11),gridcolor="#1e3054",title_font=dict(color="#ffffff")))
                st.plotly_chart(fig,use_container_width=True)

